        def discogs_group_description_data
          {:group=>{:description=>"Eponymous debut album, released on 27 July 1983. Reissued in 1985 as \"The First Album\".\r\n\r\nThe original version of the album included a 4:48 version of \"Burning Up\" with a synth-pop arrangement. On many subsequent pressings, however, a 3:41 version driven by electric guitars takes its place.\r\n\r\nSingles:\r\nhttps://www.discogs.com/Madonna-Everybody-Todo-El-Mundo/master/5423\r\n\r\nSpecial releases / Double A-sides / Repackagings:\r\nhttps://www.discogs.com/Madonna-Holiday-Everybody/master/295403"}}
        end

